function visibleTimeRange(){const full=fullTimeRange();let start=Number.isFinite(timeViewStart)?timeViewStart:full.start,end=Number.isFinite(timeViewEnd)?timeViewEnd:full.end;if(end-start<Math.max(.5,full.span/10000)){const mid=(start+end)/2,half=Math.max(.25,full.span/20000);start=mid-half;end=mid+half}if(start<full.start){end+=full.start-start;start=full.start}if(end>full.end){start-=end-full.end;end=full.end}start=Math.max(full.start,start);end=Math.min(full.end,Math.max(start+.001,end));return{start,end,span:end-start,full}}
