umber(tAt(gap))||0);y.push(null);continue}if(mode==='trend'){const mid=Math.min(len-1,Math.floor((start+end)/2));t.push(tAt(mid));y.push(count?sum/count:null)}else{const mid=Math.min(len-1,Math.floor((start+end)/2)),center=Number(tAt(mid))||0;if(minI===maxI){t.push(center);y.push(yAt(minI))}else{t.push(center);y.push(yAt(minI));t.push(center);y.push(yAt(maxI));t.push(center);y.push(null)}}}if(mode==='trend'&&y.length>2){const radius=Math.max(1,profile.smooth||5),smoothed=[];for(let i=0;i<y.length;i++){if(y[i]===null){smoothed.push(null);continue}let sum=0,count=0;for(let j=Math.max(0,i-radius);j<=Math.min(y.length-1,i+radius);j++){const v=Number(y[j]);if(Number.isFinite(v)){sum+=v;count++}}smoothed.push(count?sum/count:y[i])}const result={t,y:smoothed,rawCount:len,bucketCount};renderCache.set(cacheKey,result);return result}const result={t,y,rawCount:len,bucketCount};renderCache.set(cacheKey,result);return result}
