function initStatic(){const h=DATA.hardware||{},hd=DATA.hardwareDerived||{},fs=DATA.frameStats||{},ss=DATA.systemStats||{},cap=DATA.capture||{},targetName=(DATA.target&&(DATA.target.displayName||DATA.target.processName))||'game.exe';if(!DATA.notes.frameDataCaptured&&captureAlert){captureAlert.classList.add('show');captureAlert.innerHTML=`<b>FPS 未采集到：</b>${esc(cap.FrameCaptureMessage||DATA.notes.frameCaptureMessage||'PresentMon 没有写入有效帧数据。')}<br>状态：${esc(cap.FrameCaptureStatus||DATA.notes.frameCaptureStatus||'no-frame-data')}；CSV：${esc(cap.PresentMonCsvBytes??0)} bytes；目标：${esc(cap.TargetResolvedProcess||cap.TargetProcess||targetName)}。`}setText('gameName',targetName);setText('gameIcon',targetName.replace(/\.exe$/i,'').slice(0,2).toUpperCase()||'FS');document.title=`FrameScope - ${targetName} 性能报告`;setText('hwCpu',h.CpuName||'N/A');setText('hwCore',h.CpuCores?`${h.CpuCores} / ${h.CpuThreads}`:'N/A');setText('hwCpuClock',h.CpuMaxClockMHz?`${h.CpuMaxClockMHz} MHz`:'N/A');setText('hwGpu',h.GpuName||'N/A');setText('hwDriver',h.GpuDriver||'N/A');setText('hwVram',hd.vramTotalGb?`${n(hd.vramTotalGb,1)} GB`:'N/A');setText('hwOs',`${h.OsCaption||'Windows'} ${h.OsArch||''}`.trim());setText('hwMem',hd.totalMemoryGb?`${n(hd.totalMemoryGb,1)} GB`:'N/A');setText('hwSamples',`${DATA.counts.frames} 帧 / ${DATA.counts.processSamples} 次进程采样`);setText('runStart',`开始时间：${DATA.run.startLabel}`);setText('runEnd',`结束时间：${DATA.run.endLabel}`);setText('runDuration',`记录时长：${DATA.run.durationLabel}`);document.getElementById('gauges').innerHTML=[ring('FPS',n(fs.average,0),'平均帧',100,'#29e6ff',''),ring('处理器',`${n(ss.cpuAvg,0)}%`,'占用率',ss.cpuAvg,'#a9ff47',`峰值 ${n(ss.cpuMax,0)}%`),ring('GPU',`${n(ss.gpuAvg,0)}%`,'占用率',ss.gpuAvg,'#29e6ff',`功耗 ${n(ss.powerAvg,0)}W`),ring('显卡温度',`${n(ss.gpuTempAvg,0)}°C`,'温度',ss.gpuTempAvg,'#ffd35b',`GPU频率 ${n(ss.gpuClockAvg,0)}MHz`),ring('显存',`${n(ss.vramUsedPctAvg,0)}%`,`${n(ss.vramUsedAvg,2)}/${n(hd.vramTotalGb,1)} GB`,ss.vramUsedPctAvg,'#a9ff47',''),ring('内存',`${n(s