function drawSpikeMarkers(rendered,x,y){if(view!=='fps'||readMode.value!=='spike'||!rendered.length)return;const item=rendered[0];if(!item||item.len<5)return;let sum=0,count=0;for(let i=0;i<item.len;i++){const v=Number(item.points.y[i]);if(Number.isFinite(v)){sum+=v;count++}}if(count<5)return;const avg=sum/count,low=avg*.82,high=avg*1.22,step=Math.max(1,Math.floor(item.len/900));let marked=0;ctx.save();ctx.lineWidth=1.5;for(let i=1;i<item.len-1&&marked<180;i+=step){const v=Number(item.points.y[i]),prev=Number(item.points.y[i-1]),next=Number(item.points.y[i+1]);if(!Number.isFinite(v))continue;const lowSpike=v<low&&(!Number.isFinite(prev)||v<=prev)&&(!Number.isFinite(next)||v<=next),highSpike=v>high&&(!Number.isFinite(prev)||v>=prev)&&(!Number.isFinite(next)||v>=next);if(!lowSpike&&!highSpike)continue;const xx=x(item.points.t[i]),yy=y(v),color=lowSpike?'#ff4f78':'#ffd84a';ctx.fillStyle=color;ctx.strokeStyle='rgba(3,8,18,.95)';ctx.shadowColor=color;ctx.shadowBlur=10;ctx.beginPath();ctx.arc(xx,yy,4.2,0,Math.PI*2);ctx.fill();ctx.shadowBlur=0;ctx.stroke();marked++}ctx.restore()}
function draw(){if(!DATA)return;setTitle();buildSeries();const{w,h,pw,ph}=chartDims(),range=visibleTimeRange();clearOverlay();lastRenderStats={raw:0,drawn:0,buckets:0};ctx.clearRect(0,0,w,h);const bg=ctx.createLinearGradient(0,0,w,h);bg.addColorStop(0,'#071321');bg.addColorStop(1,'#030812');ctx.fillStyle=bg;ctx.fillRect(0,0,w,h);if(!currentTimes.length||!currentSeries.length){ctx.fillStyle='#a9bac8';ctx.font='15px Segoe UI';ctx.fillText('本视图没有可绘制的数据。',PAD.l,PAD.t+24);legend.innerHTML='';updateModeStats();return}const rendered=[];let maxY=0;for(let si=0;si<currentSeries.length;si++){const points=getRenderablePoints(currentSeries[si],pw,range),len=Math.min(points.t.length,points.y.length);rendered.push({series:currentSeries[si],points,len});lastRenderStats.raw+=points.rawCount||0;lastRenderStats.drawn+=len;lastRenderStats.buckets+=points.bucketCount||0;for(let i=0;i<len;i++){const v=Number(points.y[i]);if(Number.isFinite(v)&&v>maxY)maxY=v}}if(!Number.isFinite(Number(maxY))||Number(maxY)<=0)maxY=1;maxY=maxY*1.08;function x(sec){return PAD.l+((Number(sec)-range.start)/range.span)*pw}function y(v){return PAD.t+ph-(Number(v)/maxY)*ph}ctx.save();ctx.beginPath();ctx.rect(PAD.l,PAD.t,pw,ph);ctx.clip();ctx.strokeStyle='rgba(155,205,235,.16)';ctx.lineWidth=1;for(let i=0;i<=6;i++){const yy=PAD.t+ph/6*i;ctx.beginPath();ctx.moveTo(PAD.l,yy);ctx.lineTo(PAD.l+pw,yy);ctx.stroke()}for(let i=0;i<=10;i++){const xx=PAD.l+pw/10*i;ctx.beginPath();ctx.moveTo(xx,PAD.t);ctx.lineTo(xx,PAD.t+ph);ctx.stroke()}for(let si=0;si<rendered.length;si++){const item=rendered[si],alpha=seriesAlpha(si);ctx.strokeStyle=item.series.color;ctx.globalAlpha=alpha;ctx.lineWidth=lineWidth(si);ctx.beginPath();let started=false;for(let i=0;i<item.len;i++){const v=item.points.y[i];if(v===null||!Number.isFinite(Number(v))){started=false;continue}const xx=x(item.points.t[i]),yy=y(v);if(!started){ctx.moveTo(xx,yy);started=true}else ctx.lineTo(xx,yy)}ctx.stroke();ctx.globalAlpha=1}drawSpikeMarkers(rendered,x,y);ctx.rest