function updateModeStats(){if(!modeStats)return;const label=readMode.options[readMode.selectedIndex]?.textContent||readMode.value,range=visibleTimeRange();const raw=lastRenderStats.raw||0,drawn=lastRenderStats.drawn||0,buckets=lastRenderStats.buckets||0,windowText=range.span<range.full.span*.995?`${mmss(range.start)}-${mmss(range.end)}`:'全时段';modeStats.textContent=`${label} · ${windowText} · 绘制 ${drawn.toLocaleString()} 点 / 原始 ${raw.toLocaleString()} 点 · 桶 ${buckets.toLocaleString()}`}
function redraw(){tooltip.style.opacity=0;chartBox.classList.add('switching');window.setTimeout(()=>{draw();window.requestAnimationFrame(()=>chartBox.classList.remove('switching'))},70)}
function nearestIndex(times,sec){if(!times.length)return 0;if(sec<=Number(times[0]))return 0;let lo=0,hi=times.length-1;if(sec>=Number(times[hi]))return hi;while(hi-lo>1){const mid=(lo+hi)>>1;if(Number(times[mid])<sec)lo=mid;else hi=mid}return Math.abs(Number(times[lo])-sec)<=Math.abs(Number(times[hi])-sec)?lo:hi}
function hover(evt){const{pw,ph}=chartDims(),rect=chartBox.getBoundingClientRect(),mx=evt.clientX-rect.left,my=evt.clientY-rect.top;if(mx<PAD.l||mx>PAD.l+pw||my<PAD.t||my>PAD.t+ph){tooltip.style.opacity=0;clearOverlay();return}const range=visibleTimeRange(),sec=range.start+(mx-PAD.l)/pw*range.span,idx=nearestIndex(currentTimes,sec);clearOverlay();octx.strokeStyle='rgba(255,255,255,.62)';octx.lineWidth=1;octx.beginPath();octx.moveTo(mx,PAD.t);octx.lineTo(mx,PAD.t+ph);octx.stroke();let rows=[];if(view==='process'){const q=processSearch.value.trim().toLowerCase(),cacheKey=`${processMetric}|${q}|${idx}|${currentSeries.length}`;if(processHoverCache.has(cacheKey))rows=processHoverCache.get(cacheKey);else{for(const s of currentSeries){const v=s.data[idx];if(v!==null&&Number.isFinite(Number(v)))rows.push({name:s.name,value:v,color:s.color})}rows.sort((a,b)=>Number(b.value)-Number(a.value));rows=rows.slice(0,26);if(processHoverCache.size>4000)processHoverCache.clear();processHoverCache.set(cacheKey,rows)}}else rows=currentSeries.map(s=>({name:s.name,value:s.data[idx],color:s.color})).filter(r=>r.value!==null&&Number.isFinite(Number(r.value)));tooltip.innerHTML=`<b>${mmss(currentTimes[idx])}</b><br>`+rows.map(r=>`<span style='color:${r.color}'>■</span> ${esc(r.name)}: ${n(r.value,view==='process'&&processMetric==='mem'?1:2)} ${currentUnit}`).join('<br>');tooltip.style.left=Math.min(rect.width-470,Math.max(8,mx+14))+'px';tooltip.style.top=Math.max(8,my+14)+'px';tooltip.style.opacity=1}
function scheduleHover(evt){pendingHoverEvent=evt;if(hoverFrame)return;hoverFrame=window.requestAnimationFrame(()=>{hoverFrame=0;const e=pendingHoverEvent;pendingHoverEvent=null;if(e)hover(e)})}
function plotPoint(evt){const{pw,ph}=chartDims(),rect=chartBox.getBoundingClientRect(),mx=evt.clientX-rect.left,my=evt.clientY-rect.top;return{mx,my,pw,ph,inside:mx>=PAD.l&&mx<=PAD.l+pw&&my>=PAD.t&&my<=PAD.t+ph}}
function zoomChart(evt){const p=plotPoint(evt);if(!p.inside)return;evt.preventDefault();const range=visibleTimeRange(),ratio=(p.mx-PAD.l)/p.pw,focus=range.start+ratio*range.span,full=range.full,minSpan=Math.max(.5,full.span/2000),zoom=evt.deltaY<0?.78:1.28,newSpan=Math.max(minSpan,Math.min(full.span,range.span*zoom)),nextStart=focus-newSpan*ratio;setTimeView(nextStart,nextStart+newSpan);hover(evt)}
function startPan(evt){if(evt.button!==0)return;const p=plotPoint(evt);if(!p.inside)return;const range=visibleTimeRange();dragState={x:evt.clientX,start:range.start,end:range.end,span:range.span,moved:false};chartBox.classList.add('dragging');tooltip.style.opacity=0;evt.preventDefault()}
