function exportChartPng(){draw();const out=document.createElement('canvas'),scale=2,w=1600,h=1000;out.width=w*scale;out.height=h*scale;const c=out.getContext('2d');c.scale(scale,scale);const bg=c.createLinearGradient(0,0,w,h);bg.addColorStop(0,'#030812');bg.addColorStop(1,'#071321');c.fillStyle=bg;c.fillRect(0,0,w,h);c.fillStyle='#eff7ff';c.font='700 30px Segoe UI';c.fillText((DATA.target&&(DATA.target.displayName||DATA.target.processName))||'FrameScope',42,54);c.fillStyle='#a9bac8';c.font='15px Segoe UI';c.fillText(`${viewTitle.textContent} · ${readMode.options[readMode.selectedIndex]?.textContent||readMode.value} · ${DATA.run.durationLabel}`,42,84);c.fillText(modeStats.textContent||'',42,108);canvasRoundRect(c,42,130,1516,820,26);c.fillStyle='#071321';c.fill();c.save();canvasRoundRect(c,42,130,1516,820,26);c.clip();c.drawImage(canvas,0,0,canvas.width,canvas.height,42,130,1516,820);c.restore();c.strokeStyle='rgba(0,217,255,.58)';c.lineWidth=2;canvasRoundRect(c,42,130,1516,820,26);c.stroke();const a=document.createElement('a');a.download=`framescope-${view}-${readMode.value}.png`;a.href=out.toDataURL('image/png');a.click()}
if(DATA){document.querySelectorAll('.tab').forEach(btn=>btn.addEventListener('click',()=>{document.querySelectorAll('.tab').forEach(b=>b.classList.remove('active'));btn.classList.add('active');view=btn.dataset.view;processHoverCache.clear();setOptions();redraw()}));metricSelect.addEventListener('change',()=>{if(view==='fps')fpsMetric=metricSelect.value;else if(view==='perf')perfMetric=metricSelect.value;else if(view==='system')systemMetric=metricSelect.value;else if(view==='io')ioMetric=metricSelect.value;else processMetric=metricSelect.value;processHoverCache.clear();redraw()});processSearch.addEventListener('input',()=>{renderCache.clear();processHoverCache.clear();legendKey='';draw()});readMode.addEventListener('change',()=>{renderCache.clear();processHoverCache.clear();redraw()});widthScale.addEventListener('input',applyWidth);document.getElementById('fitWidth').addEventListener('click',()=>{widthScale.value=1;applyWidth()});document.getElementById('resetView').addEventListener('click',resetTimeView);document.getElementById('exportPng').addEventListener('click',exportChartPng);chartBox.addEventListener('wheel',zoomChart,{passive:false});chartBox.addEventListener('mousedown',startPan);chartBox.addEventListener('mousemove',movePan);window.addEventListener('mouseup',endPan);chartBox.addEventListener('mouseleave',()=>{if(!dragState){tooltip.style.opacity=0;clearOverlay()}});window.addEventListener('resize',()=>applyWidth());if(window.ResizeObserver){resizeObserver=new ResizeObserver(()=>{renderCache.clear();processHoverCache.clear();resizeCanvas()});resizeObserver.observe(chartBox)}initStatic();setOptions();applyWidth()}
